INSERT INTO `wp_commentmeta` (`meta_id`, `comment_id`, `meta_key`, `meta_value`) VALUES (1136,284,'akismet_as_submitted','a:32:{s:14:\"comment_author\";s:16:\"Dr Sanjay narula\";s:20:\"comment_author_email\";s:0:\"\";s:18:\"comment_author_url\";s:0:\"\";s:15:\"comment_content\";s:977:\"Good evening everyone,  i am dr sanjay narula a surgeon and medicolegal consultant and partner of dr P k Kohli in KN MEDICOLEGAL SUPPORT. I am N in KN.I Quote actual cases from my vast experience of presiding over more than 700 medicolegal enquiries in 20 years.\r\nOn subject of what\'s app consultation i am reminded of a case where a patient operated for lap hysterectomy in a corporate hospital was discharged after2 days, on 3rd day patient calls surgeon that he was having some discomfort and sent a what\'s app message,doctor being busy somewhere replied to take some medicine ,pantos etc.exchange of messages continued for next 2 days when finally pt came after 3 days, she was having peritonitis, underwent laparotomy for gut injury, finally died due to sepsis. Complaint filed by patient had a bundle of print of what\'s app exchanges as prime evidence\r\nSo we must be careful specially in post operative patients and always ask patient to come back to hospital immediately\";s:12:\"comment_type\";s:7:\"comment\";s:7:\"user_id\";i:0;s:7:\"user_ID\";i:0;s:17:\"comment_author_IP\";s:13:\"49.36.144.139\";s:13:\"comment_agent\";s:111:\"Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Mobile Safari/537.36\";s:7:\"user_ip\";s:13:\"49.36.144.139\";s:10:\"user_agent\";s:111:\"Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Mobile Safari/537.36\";s:4:\"blog\";s:24:\"https://diapindia.org.in\";s:9:\"blog_lang\";s:5:\"en_US\";s:12:\"blog_charset\";s:5:\"UTF-8\";s:9:\"permalink\";s:58:\"https://diapindia.org.in/event/iap-medicolegal-chapter-16/\";s:19:\"POST_ak_hp_textarea\";s:0:\"\";s:10:\"POST_ak_js\";s:13:\"177998